14	// TestServer_SingletonGuardRefusesSecondLaunch verifies that once the
15	// singleton lock is held by an alive process, a second acquisition refuses
16	// with a SingletonLockError naming the holder pid and recorded URL.
17	func TestServer_SingletonGuardRefusesSecondLaunch(t *testing.T) {
18		t.Setenv("XDG_DATA_HOME", t.TempDir())
19	
20		// Pretend a server has already written its address file (so the error
21		// message can include the URL of the running server).
22		dir := serverAddrDir()
23		if err := os.MkdirAll(dir, 0700); err != nil {
24			t.Fatalf("mkdir: %v", err)
25		}
26		addr := map[string]any{
27			"url": "https://127.0.0.1:7743",
28			"pid": os.Getpid(),
29		}
30		data, _ := json.Marshal(addr)
31		if err := os.WriteFile(filepath.Join(dir, "server.addr"), data, 0600); err != nil {
32			t.Fatalf("write addr: %v", err)
33		}
34	
35		// First acquisition succeeds.
36		release1, err := acquireSingletonLock()
37		if err != nil {
38			t.Fatalf("first acquire failed: %v", err)
39		}
40		defer release1()
41	
42		// Second acquisition (same pid is the holder; the function detects this
43		// because the lock dir exists with our pid recorded — but since the
44		// caller is the same process, processAlive returns true and we get a
45		// SingletonLockError).
46		_, err = acquireSingletonLock()
47		if err == nil {
48			t.Fatal("expected second acquire to fail, got nil")
49		}
50		var sle *SingletonLockError
51		if !errors.As(err, &sle) {
52			t.Fatalf("expected *SingletonLockError, got %T: %v", err, err)
53		}
54		if sle.PID != os.Getpid() {
55			t.Errorf("expected error pid=%d, got %d", os.Getpid(), sle.PID)
56		}
57		if !strings.Contains(sle.Addr, "7743") {
58			t.Errorf("expected error addr to contain 7743, got %q", sle.Addr)
59		}
60		if !strings.Contains(err.Error(), "already running") {
61			t.Errorf("expected 'already running' in message, got %q", err.Error())
62		}
63	
64		// Verify pid file exists and matches our pid.
65		pidData, err := os.ReadFile(filepath.Join(dir, "server.lock", "pid"))
66		if err != nil {
67			t.Fatalf("read lock pid: %v", err)
68		}
69		pid, _ := strconv.Atoi(strings.TrimSpace(string(pidData)))
70		if pid != os.Getpid() {
71			t.Errorf("expected lock pid=%d, got %d", os.Getpid(), pid)
72		}
73	}
