75	// TestServer_SingletonGuardBreaksStaleLock verifies that if the recorded lock
76	// pid is dead, a fresh acquire breaks the stale lock and succeeds.
77	func TestServer_SingletonGuardBreaksStaleLock(t *testing.T) {
78		t.Setenv("XDG_DATA_HOME", t.TempDir())
79	
80		dir := serverAddrDir()
81		if err := os.MkdirAll(dir, 0700); err != nil {
82			t.Fatalf("mkdir: %v", err)
83		}
84		lockDir := filepath.Join(dir, "server.lock")
85		if err := os.Mkdir(lockDir, 0700); err != nil {
86			t.Fatalf("mkdir lock: %v", err)
87		}
88		// PID 999999 is overwhelmingly unlikely to exist.
89		if err := os.WriteFile(filepath.Join(lockDir, "pid"), []byte("999999"), 0600); err != nil {
90			t.Fatalf("write stale pid: %v", err)
91		}
92	
93		release, err := acquireSingletonLock()
94		if err != nil {
95			t.Fatalf("expected stale lock to be broken, got error: %v", err)
96		}
97		defer release()
98	
99		pidData, _ := os.ReadFile(filepath.Join(lockDir, "pid"))
100		pid, _ := strconv.Atoi(strings.TrimSpace(string(pidData)))
101		if pid != os.Getpid() {
102			t.Errorf("expected our pid in lock after break, got %d", pid)
103		}
104	}
