106	// TestServer_StaleAddressFallbackWithWarning verifies that ReadServerAddr
107	// detects a server.addr whose recorded pid is not alive, emits a warning,
108	// and returns "" so callers fall back to the default URL.
109	func TestServer_StaleAddressFallbackWithWarning(t *testing.T) {
110		t.Setenv("XDG_DATA_HOME", t.TempDir())
111	
112		dir := serverAddrDir()
113		if err := os.MkdirAll(dir, 0700); err != nil {
114			t.Fatalf("mkdir: %v", err)
115		}
116		stalePID := 999999
117		addr := map[string]any{
118			"url": "https://127.0.0.1:18099",
119			"pid": stalePID,
120		}
121		data, _ := json.Marshal(addr)
122		addrPath := filepath.Join(dir, "server.addr")
123		if err := os.WriteFile(addrPath, data, 0600); err != nil {
124			t.Fatalf("write addr: %v", err)
125		}
126	
127		var buf bytes.Buffer
128		prev := addrFallbackWarnWriter
129		addrFallbackWarnWriter = &buf
130		defer func() { addrFallbackWarnWriter = prev }()
131	
132		got := ReadServerAddr()
133		if got != "" {
134			t.Errorf("expected ReadServerAddr to return empty for dead pid, got %q", got)
135		}
136		if !strings.Contains(buf.String(), "dead pid") {
137			t.Errorf("expected 'dead pid' warning, got %q", buf.String())
138		}
139		if !strings.Contains(buf.String(), "127.0.0.1:7743") {
140			t.Errorf("expected fallback URL in warning, got %q", buf.String())
141		}
142		// Stale file should be removed best-effort.
143		if _, err := os.Stat(addrPath); !os.IsNotExist(err) {
144			t.Errorf("expected stale addr file removed, stat err=%v", err)
145		}
146	}
